/* ------------------------------------------------------------------ */
/*  Watercolor SVG building blocks                                    */
/* ------------------------------------------------------------------ */
const Poppy = ({ size = 80, hue = "rose" }) => {
  const c = hue === "rose" ? "var(--rose)" : hue === "blue" ? "var(--cornflower)" : "var(--sage)";
  const cd = hue === "rose" ? "var(--rose-deep)" : hue === "blue" ? "var(--cornflower-deep)" : "var(--sage-deep)";
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" style={{ overflow: "visible" }}>
      <g opacity="0.85">
        <ellipse cx="50" cy="50" rx="30" ry="22" fill={c} opacity="0.45" transform="rotate(-15 50 50)" />
        <ellipse cx="48" cy="46" rx="24" ry="28" fill={c} opacity="0.55" transform="rotate(20 48 46)" />
        <ellipse cx="52" cy="52" rx="20" ry="18" fill={cd} opacity="0.35" transform="rotate(-30 52 52)" />
        <ellipse cx="50" cy="50" rx="14" ry="12" fill={cd} opacity="0.45" />
        <circle cx="50" cy="50" r="5" fill="var(--ink)" opacity="0.55" />
        <circle cx="50" cy="50" r="3" fill="var(--gold)" opacity="0.8" />
      </g>
    </svg>
  );
};

const Daisy = ({ size = 60 }) => (
  <svg width={size} height={size} viewBox="0 0 100 100" style={{ overflow: "visible" }}>
    <g opacity="0.85">
      {[0, 45, 90, 135, 180, 225, 270, 315].map((a, i) => (
        <ellipse key={i} cx="50" cy="28" rx="7" ry="16" fill="var(--cream)"
          stroke="var(--rose-soft)" strokeWidth="0.6"
          transform={`rotate(${a} 50 50)`} opacity="0.9" />
      ))}
      <circle cx="50" cy="50" r="8" fill="var(--gold)" opacity="0.9" />
      <circle cx="50" cy="50" r="5" fill="var(--gold-light)" opacity="0.8" />
    </g>
  </svg>
);

const Cornflower = ({ size = 55 }) => (
  <svg width={size} height={size} viewBox="0 0 100 100" style={{ overflow: "visible" }}>
    <g opacity="0.85">
      {[0, 30, 60, 90, 120, 150, 180, 210, 240, 270, 300, 330].map((a, i) => (
        <path key={i} d="M50 50 L46 28 Q50 18 54 28 Z" fill="var(--cornflower)"
          opacity="0.7" transform={`rotate(${a} 50 50)`} />
      ))}
      <circle cx="50" cy="50" r="6" fill="var(--cornflower-deep)" />
      <circle cx="50" cy="50" r="3" fill="var(--ink)" opacity="0.6" />
    </g>
  </svg>
);

const Sprig = ({ size = 90, rotate = 0 }) => (
  <svg width={size} height={size * 1.4} viewBox="0 0 100 140" style={{ overflow: "visible", transform: `rotate(${rotate}deg)` }}>
    <g opacity="0.8">
      <path d="M50 130 Q48 80 52 30" stroke="var(--sage-deep)" strokeWidth="1.5" fill="none" opacity="0.7" />
      {[20, 40, 60, 80, 100].map((y, i) => (
        <g key={i}>
          <ellipse cx={i % 2 === 0 ? 38 : 64} cy={y} rx="13" ry="6" fill="var(--sage)"
            opacity="0.7" transform={`rotate(${i % 2 === 0 ? -30 : 30} ${i % 2 === 0 ? 38 : 64} ${y})`} />
          <ellipse cx={i % 2 === 0 ? 38 : 64} cy={y} rx="11" ry="4" fill="var(--sage-deep)"
            opacity="0.4" transform={`rotate(${i % 2 === 0 ? -30 : 30} ${i % 2 === 0 ? 38 : 64} ${y})`} />
        </g>
      ))}
    </g>
  </svg>
);

const Berries = ({ size = 50 }) => (
  <svg width={size} height={size} viewBox="0 0 100 100" style={{ overflow: "visible" }}>
    <g opacity="0.85">
      <circle cx="35" cy="55" r="8" fill="var(--rose-deep)" opacity="0.7" />
      <circle cx="55" cy="40" r="9" fill="var(--rose)" opacity="0.7" />
      <circle cx="65" cy="62" r="7" fill="var(--rose-deep)" opacity="0.65" />
      <circle cx="45" cy="70" r="6" fill="var(--rose)" opacity="0.6" />
      <path d="M50 30 Q45 50 35 55 M50 30 Q55 38 55 40 M50 30 Q60 50 65 62"
        stroke="var(--sage-deep)" strokeWidth="1" fill="none" opacity="0.6" />
    </g>
  </svg>
);

/* ------------------------------------------------------------------ */
/*  Floral border with parallax                                       */
/* ------------------------------------------------------------------ */
const FloralBorder = ({ tilt }) => {
  const tx = (tilt?.gamma || 0) * 0.6;
  const ty = (tilt?.beta || 0) * 0.4;
  return (
    <>
      <div className="absolute top-0 left-0 pointer-events-none" style={{ transform: `translate(${-tx * 0.5}px, ${-ty * 0.5}px)` }}>
        <div className="sway-slow"><Sprig size={120} rotate={-30} /></div>
      </div>
      <div className="absolute top-4 left-12 pointer-events-none" style={{ transform: `translate(${-tx * 1.0}px, ${-ty * 1.0}px)` }}>
        <div className="sway-med"><Poppy size={70} hue="rose" /></div>
      </div>
      <div className="absolute top-20 left-2 pointer-events-none" style={{ transform: `translate(${-tx * 1.4}px, ${-ty * 1.4}px)` }}>
        <Cornflower size={45} />
      </div>

      <div className="absolute top-0 right-0 pointer-events-none" style={{ transform: `translate(${tx * 0.5}px, ${-ty * 0.5}px) scaleX(-1)` }}>
        <div className="sway-slow"><Sprig size={110} rotate={-20} /></div>
      </div>
      <div className="absolute top-8 right-10 pointer-events-none" style={{ transform: `translate(${tx * 1.0}px, ${-ty * 1.0}px)` }}>
        <div className="sway-med"><Daisy size={55} /></div>
      </div>
      <div className="absolute top-24 right-4 pointer-events-none" style={{ transform: `translate(${tx * 1.4}px, ${-ty * 1.4}px)` }}>
        <Cornflower size={40} />
      </div>

      <div className="absolute -bottom-2 left-0 pointer-events-none" style={{ transform: `translate(${-tx * 0.6}px, ${ty * 0.6}px)` }}>
        <div className="sway-slow"><Sprig size={130} rotate={170} /></div>
      </div>
      <div className="absolute bottom-6 left-14 pointer-events-none" style={{ transform: `translate(${-tx * 1.1}px, ${ty * 1.1}px)` }}>
        <div className="sway-med"><Berries size={45} /></div>
      </div>

      <div className="absolute -bottom-2 right-0 pointer-events-none" style={{ transform: `translate(${tx * 0.6}px, ${ty * 0.6}px) scaleX(-1)` }}>
        <div className="sway-slow"><Sprig size={130} rotate={170} /></div>
      </div>
      <div className="absolute bottom-8 right-12 pointer-events-none" style={{ transform: `translate(${tx * 1.1}px, ${ty * 1.1}px)` }}>
        <div className="sway-med"><Poppy size={60} hue="blue" /></div>
      </div>
    </>
  );
};

